import csv
import json
from datetime import datetime
from pathlib import Path

def _parse_ts(value):
    if not value:
        return None
    value = value.strip()
    if value.endswith('Z'):
        value = value[:-1] + '+00:00'
    try:
        return datetime.fromisoformat(value)
    except Exception:
        return None

def transform(input_data):
    cfg = input_data if isinstance(input_data, dict) else {}
    input_path = Path(cfg.get('input_path', 'backend/.runs/demo/incremental-events.csv'))
    state_path = Path(cfg.get('state_path', 'backend/.runs/demo/incremental-state.json'))
    output_path = Path(cfg.get('output_path', 'backend/.runs/demo/incremental-latest.json'))

    state_path.parent.mkdir(parents=True, exist_ok=True)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    last_ts = datetime.fromisoformat('1970-01-01T00:00:00+00:00')
    if state_path.exists():
        try:
            state = json.loads(state_path.read_text())
            loaded = _parse_ts(str(state.get('last_ts', '')))
            if loaded is not None:
                last_ts = loaded
        except Exception:
            pass

    upserted = {}
    rows_seen = 0
    rows_new = 0
    max_ts = last_ts

    with input_path.open('r', newline='', encoding='utf-8') as src:
        reader = csv.DictReader(src)
        for row in reader:
            rows_seen += 1
            row_id = str(row.get('id', '')).strip()
            row_ts = _parse_ts(str(row.get('updated_at', '')))
            if not row_id or row_ts is None:
                continue
            if row_ts <= last_ts:
                continue

            rows_new += 1
            if row_ts > max_ts:
                max_ts = row_ts

            upserted[row_id] = {
                'id': row_id,
                'updated_at': row_ts.isoformat(),
                'value': row.get('value'),
            }

    output_path.write_text(json.dumps({'records': list(upserted.values())}, indent=2))
    state_path.write_text(json.dumps({'last_ts': max_ts.isoformat()}, indent=2))

    return {
        'job': 'incremental_watermark',
        'input_path': str(input_path),
        'output_path': str(output_path),
        'state_path': str(state_path),
        'rows_seen': rows_seen,
        'rows_new': rows_new,
        'watermark': max_ts.isoformat(),
    }
